-- Item Special Sewing (Shozin Exchange / Crafting) table
-- Migrated from MSSQL ITEM_SPECIAL_SEWING (2468 rows)

CREATE TABLE IF NOT EXISTS item_special_sewing (
    n_index INTEGER NOT NULL PRIMARY KEY,
    description VARCHAR(300),
    req_item_id_1 INTEGER NOT NULL DEFAULT 0,
    req_item_count_1 INTEGER NOT NULL DEFAULT 0,
    req_item_id_2 INTEGER NOT NULL DEFAULT 0,
    req_item_count_2 INTEGER NOT NULL DEFAULT 0,
    req_item_id_3 INTEGER NOT NULL DEFAULT 0,
    req_item_count_3 INTEGER NOT NULL DEFAULT 0,
    req_item_id_4 INTEGER NOT NULL DEFAULT 0,
    req_item_count_4 INTEGER NOT NULL DEFAULT 0,
    req_item_id_5 INTEGER NOT NULL DEFAULT 0,
    req_item_count_5 INTEGER NOT NULL DEFAULT 0,
    req_item_id_6 INTEGER NOT NULL DEFAULT 0,
    req_item_count_6 INTEGER NOT NULL DEFAULT 0,
    req_item_id_7 INTEGER NOT NULL DEFAULT 0,
    req_item_count_7 INTEGER NOT NULL DEFAULT 0,
    req_item_id_8 INTEGER NOT NULL DEFAULT 0,
    req_item_count_8 INTEGER NOT NULL DEFAULT 0,
    req_item_id_9 INTEGER NOT NULL DEFAULT 0,
    req_item_count_9 INTEGER NOT NULL DEFAULT 0,
    req_item_id_10 INTEGER NOT NULL DEFAULT 0,
    req_item_count_10 INTEGER NOT NULL DEFAULT 0,
    give_item_id INTEGER NOT NULL DEFAULT 0,
    give_item_count INTEGER NOT NULL DEFAULT 0,
    success_rate INTEGER NOT NULL DEFAULT 0,
    npc_id SMALLINT NOT NULL DEFAULT 0,
    is_notice BOOLEAN NOT NULL DEFAULT FALSE,
    is_shadow_success BOOLEAN NOT NULL DEFAULT FALSE
);

CREATE INDEX IF NOT EXISTS idx_item_special_sewing_npc ON item_special_sewing (npc_id);

